from cryptography.fernet import Fernet

# Function to generate a new encryption key and save it to the config file
def generate_key_and_save(config_file_path):
    key = Fernet.generate_key()
    with open(config_file_path, 'wb') as key_file:
        key_file.write(key)

# Function to load the encryption key from the config file
def load_key_from_config(config_file_path):
    with open(config_file_path, 'rb') as key_file:
        return key_file.read()

# Function to encrypt a credit card number
def encrypt_credit_card(credit_card_number, config_file_path):
    key = load_key_from_config(config_file_path)
    fernet = Fernet(key)
    encrypted_credit_card = fernet.encrypt(credit_card_number.encode())
    return encrypted_credit_card

# Function to decrypt a credit card number
def decrypt_credit_card(encrypted_credit_card, config_file_path):
    key = load_key_from_config(config_file_path)
    fernet = Fernet(key)
    decrypted_credit_card = fernet.decrypt(encrypted_credit_card).decode()
    return decrypted_credit_card

